code = """import json, pandas as pd, re

# Load business query result (may be file path)
biz = var_call_lvrCIX5IQN7P289H4mOlBHZn
if isinstance(biz, str):
    with open(biz, 'r', encoding='utf-8') as f:
        biz = json.load(f)

rev = var_call_f0Jz9Xr5I2VqSol7Kir9KkRs

biz_df = pd.DataFrame(biz)
rev_df = pd.DataFrame(rev)

# parse hours stored as string representation of list or None

def parse_hours(val):
    if val is None:
        return None
    if isinstance(val, list):
        return val
    if isinstance(val, str):
        s = val.strip()
        if s.lower() == 'none':
            return None
        try:
            return json.loads(s)
        except Exception:
            # sometimes stored with single quotes
            try:
                return json.loads(s.replace("'", '"'))
            except Exception:
                return None
    return None

biz_df['hours_parsed'] = biz_df['hours'].apply(parse_hours)

weekday_set = {'Monday','Tuesday','Wednesday','Thursday','Friday'}

# time parsing helpers

def to_minutes(t):
    t = t.strip()
    m = re.fullmatch(r'(\d{1,2})(?::(\d{2}))?\s*(AM|PM)', t, re.IGNORECASE)
    if not m:
        return None
    hh = int(m.group(1))
    mm = int(m.group(2) or 0)
    ap = m.group(3).upper()
    if hh == 12:
        hh = 0
    if ap == 'PM':
        hh += 12
    return hh*60+mm


def closes_after_6(range_str):
    s = range_str.strip()
    if s.lower() == 'closed':
        return False
    if 'Open 24 hours' in s:
        return True
    # handle multiple intervals separated by e.g. '⋅' or ','
    # but main data uses en dash
    parts = re.split(r'\s*[\u22c5,;]\s*', s)
    for p in parts:
        if '–' in p:
            start,end = [x.strip() for x in p.split('–',1)]
        elif '-' in p:
            start,end = [x.strip() for x in p.split('-',1)]
        else:
            continue
        end_min = to_minutes(end)
        start_min = to_minutes(start)
        if end_min is None:
            continue
        # if end <= start, assume closes after midnight => definitely after 6pm
        if start_min is not None and end_min <= start_min:
            return True
        if end_min > 18*60:
            return True
    return False


def qualifies(hours_list):
    if not hours_list:
        return False
    for day, hrs in hours_list:
        if day in weekday_set and isinstance(hrs, str) and closes_after_6(hrs):
            return True
    return False

biz_df = biz_df[biz_df['hours_parsed'].apply(qualifies)]

# join with ratings
rev_df['avg_rating'] = rev_df['avg_rating'].astype(float)
rev_df['review_count'] = rev_df['review_count'].astype(int)

merged = biz_df.merge(rev_df, on='gmap_id', how='inner')

# select top 5 by avg_rating desc
merged = merged.sort_values(['avg_rating','review_count'], ascending=[False, False]).head(5)

# format hours back into readable multi-line string

def fmt_hours(h):
    if not h:
        return None
    return '; '.join([f"{d}: {hrs}" for d,hrs in h])

out = []
for _, r in merged.iterrows():
    out.append({
        'name': r['name'],
        'operating_hours': fmt_hours(r['hours_parsed']),
        'avg_rating': round(float(r['avg_rating']), 3)
    })

print('__RESULT__:')
print(json.dumps(out))"""

